const A=$('#d-a'), B=$('#d-b'), Av=$('#d-av'), Bv=$('#d-bv');
const svg=$('#d-svg'), out=$('#d-out');
const nodeBtn=$('#d-node'), cuspBtn=$('#d-cusp');
const W=560,H=360,PAD=24;
const XMIN=-2.4,XMAX=2.4,YMIN=-2.8,YMAX=2.8;
const sx=x=>PAD+(x-XMIN)/(XMAX-XMIN)*(W-2*PAD);
const sy=y=>H-PAD-(y-YMIN)/(YMAX-YMIN)*(H-2*PAD);

function render(){
  const a=+A.value, b=+B.value;
  Av.textContent=a.toFixed(2); Bv.textContent=b.toFixed(2);
  const D=-16*(4*a*a*a+27*b*b);
  svg.innerHTML='';
  // axes
  svg.appendChild(SVG('line',{x1:PAD,y1:sy(0),x2:W-PAD,y2:sy(0),stroke:'#2a3242'}));
  svg.appendChild(SVG('line',{x1:sx(0),y1:PAD,x2:sx(0),y2:H-PAD,stroke:'#2a3242'}));
  // curve y^2 = f(x)
  const N=700;
  let up=[], dn=[];
  for(let i=0;i<=N;i++){
    const x=XMIN+(XMAX-XMIN)*i/N;
    const r=x*x*x+a*x+b;
    if(r<0){
      if(up.length>1){
        let d='M '+up.map(p=>p[0]+' '+p[1]).join(' L ');
        svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--blue)','stroke-width':1.7}));
        d='M '+dn.map(p=>p[0]+' '+p[1]).join(' L ');
        svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--blue)','stroke-width':1.7}));
      }
      up=[]; dn=[];
    } else {
      const y=Math.sqrt(r);
      up.push([sx(x),sy(y)]);
      dn.push([sx(x),sy(-y)]);
    }
  }
  if(up.length>1){
    let d='M '+up.map(p=>p[0]+' '+p[1]).join(' L ');
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--blue)','stroke-width':1.7}));
    d='M '+dn.map(p=>p[0]+' '+p[1]).join(' L ');
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--blue)','stroke-width':1.7}));
  }
  // mark singular point if near
  let msg='Δ = -16(4a³ + 27b²) = '+D.toFixed(3)+'\n';
  if(Math.abs(D)<0.15){
    // singular: f has a double root at x0 with f(x0)=0, f'(x0)=0 => x0=±sqrt(-a/3)
    const disc=-a/3;
    if(disc>=0){
      const x0a=Math.sqrt(disc), x0b=-Math.sqrt(disc);
      const va=x0a**3+a*x0a+b, vb=x0b**3+a*x0b+b;
      const x0 = Math.abs(va)<Math.abs(vb)?x0a:x0b;
      svg.appendChild(SVG('circle',{cx:sx(x0),cy:sy(0),r:5,fill:'var(--pink)'}));
      svg.appendChild(SVG('text',{x:sx(x0)+10,y:sy(0)-6,'font-size':12,fill:'var(--pink)'})).textContent='singular';
      msg += (Math.abs(a)<0.05?'cusp forming at origin (a→0, b→0).':'node forming.');
    } else {
      msg += 'Δ≈0 but no real singular point visible.';
    }
  } else if(D>0){
    msg += 'smooth, two real components (oval + unbounded arm).';
  } else {
    msg += 'smooth, one real component.';
  }
  out.textContent=msg;
}
A.addEventListener('input',render);
B.addEventListener('input',render);
nodeBtn.addEventListener('click',()=>{ A.value=-3; B.value=2; render(); });
cuspBtn.addEventListener('click',()=>{ A.value=0; B.value=0; render(); });
render();

