function sy(y){ return H-PAD-(y-YMIN)/(YMAX-YMIN)*(H-2*PAD); }
function plot(panel,f,color){
  const N=900;
  let up=[],dn=[];
  for(let i=0;i<=N;i++){
    const x=XMIN+(XMAX-XMIN)*i/N;
    const r=f(x);
    if(r<0){
      if(up.length>1){
        svg.appendChild(SVG('path',{d:'M '+up.map(p=>p[0]+' '+p[1]).join(' L '),fill:'none',stroke:color,'stroke-width':1.8}));
        svg.appendChild(SVG('path',{d:'M '+dn.map(p=>p[0]+' '+p[1]).join(' L '),fill:'none',stroke:color,'stroke-width':1.8}));
      }
      up=[];dn=[];
    } else {
      const y=Math.sqrt(r);
      up.push([sx(panel,x),sy(y)]);
      dn.push([sx(panel,x),sy(-y)]);
    }
  }
  if(up.length>1){
    svg.appendChild(SVG('path',{d:'M '+up.map(p=>p[0]+' '+p[1]).join(' L '),fill:'none',stroke:color,'stroke-width':1.8}));
    svg.appendChild(SVG('path',{d:'M '+dn.map(p=>p[0]+' '+p[1]).join(' L '),fill:'none',stroke:color,'stroke-width':1.8}));
  }
}
function axes(panel){
  svg.appendChild(SVG('line',{x1:sx(panel,XMIN),y1:sy(0),x2:sx(panel,XMAX),y2:sy(0),stroke:'#2a3242'}));
  svg.appendChild(SVG('line',{x1:sx(panel,0),y1:PAD,x2:sx(panel,0),y2:H-PAD,stroke:'#2a3242'}));
}
// divider
svg.appendChild(SVG('line',{x1:halfW,y1:0,x2:halfW,y2:H,stroke:'#2a3242','stroke-dasharray':'3 4'}));
// Node
axes(0);
plot(0,x=>x*x*x+x*x,'var(--blue)');
// tangents y = ±x at origin
for(const s of [1,-1]){
  svg.appendChild(SVG('line',{x1:sx(0,-1.1),y1:sy(-1.1*s),x2:sx(0,1.1),y2:sy(1.1*s),stroke:'var(--yellow)','stroke-width':1,'stroke-dasharray':'4 3',opacity:0.8}));
