const t1=SVG('text',{x:sx(0,(XMAX+XMIN)/2),y:22,'font-size':13,fill:'#fff','text-anchor':'middle','font-weight':600});
t1.textContent='y² = x³ + x²  (node)';
svg.appendChild(t1);
const t1b=SVG('text',{x:sx(0,0)-60,y:sy(0)-8,'font-size':11,fill:'var(--yellow)'});
t1b.textContent='two tangents: y = ±x';
svg.appendChild(t1b);

// Cusp
axes(1);
plot(1,x=>x*x*x,'var(--green)');
// tangent y=0 with multiplicity 2
svg.appendChild(SVG('line',{x1:sx(1,XMIN),y1:sy(0),x2:sx(1,XMAX),y2:sy(0),stroke:'var(--yellow)','stroke-width':2.5,'stroke-dasharray':'4 3',opacity:0.9}));
svg.appendChild(SVG('circle',{cx:sx(1,0),cy:sy(0),r:5,fill:'var(--pink)'}));
const t2=SVG('text',{x:sx(1,(XMAX+XMIN)/2),y:22,'font-size':13,fill:'#fff','text-anchor':'middle','font-weight':600});
t2.textContent='y² = x³  (cusp)';
svg.appendChild(t2);
const t2b=SVG('text',{x:sx(1,0.4),y:sy(0)-8,'font-size':11,fill:'var(--yellow)'});
t2b.textContent='one tangent (mult 2): y = 0';
svg.appendChild(t2b);

