const svg=$('#pm-svg'), tsl=$('#pm-t'), tv=$('#pm-tv'), out=$('#pm-out');
const radios=$$('input[name="pm"]');
const W=560,H=360,PAD=28;
const XMIN=-1.4,XMAX=2.8,YMIN=-2.6,YMAX=2.6;
const sx=x=>PAD+(x-XMIN)/(XMAX-XMIN)*(W-2*PAD);
const sy=y=>H-PAD-(y-YMIN)/(YMAX-YMIN)*(H-2*PAD);
function mode(){ return radios.find(r=>r.checked).value; }
function render(){
  const m=mode(), t=+tsl.value;
  tv.textContent=t.toFixed(2);
  svg.innerHTML='';
  svg.appendChild(SVG('line',{x1:PAD,y1:sy(0),x2:W-PAD,y2:sy(0),stroke:'#2a3242'}));
  svg.appendChild(SVG('line',{x1:sx(0),y1:PAD,x2:sx(0),y2:H-PAD,stroke:'#2a3242'}));
  // plot curve
  const N=900;
  let up=[],dn=[];
  const f=m==='node'?(x=>x*x*x+x*x):(x=>x*x*x);
  for(let i=0;i<=N;i++){
    const x=XMIN+(XMAX-XMIN)*i/N;
    const r=f(x);
    if(r<0){
      if(up.length>1){
        svg.appendChild(SVG('path',{d:'M '+up.map(p=>p[0]+' '+p[1]).join(' L '),fill:'none',stroke:'var(--blue)','stroke-width':1.7}));
        svg.appendChild(SVG('path',{d:'M '+dn.map(p=>p[0]+' '+p[1]).join(' L '),fill:'none',stroke:'var(--blue)','stroke-width':1.7}));
      }
      up=[];dn=[];
    } else {
      const y=Math.sqrt(r);
      up.push([sx(x),sy(y)]); dn.push([sx(x),sy(-y)]);
    }
  }
  if(up.length>1){
    svg.appendChild(SVG('path',{d:'M '+up.map(p=>p[0]+' '+p[1]).join(' L '),fill:'none',stroke:'var(--blue)','stroke-width':1.7}));
    svg.appendChild(SVG('path',{d:'M '+dn.map(p=>p[0]+' '+p[1]).join(' L '),fill:'none',stroke:'var(--blue)','stroke-width':1.7}));
  }
  // singular point
  svg.appendChild(SVG('circle',{cx:sx(0),cy:sy(0),r:5,fill:'var(--pink)'}));
  // parametrized point
  let px,py,info;
  if(m==='node'){
    // (t^2-1, t(t^2-1))
    px=t*t-1; py=t*(t*t-1);
    info = '(x, y) = (t²-1, t(t²-1))\n';
    info+= 't='+t.toFixed(3)+'  ↦  ('+px.toFixed(3)+', '+py.toFixed(3)+')\n';
    info+= 'group law: t₁·t₂ (multiplication in 𝔾ₘ)';
  } else {
    px=t*t; py=t*t*t;
    info = '(x, y) = (t², t³)\n';
    info+= 't='+t.toFixed(3)+'  ↦  ('+px.toFixed(3)+', '+py.toFixed(3)+')\n';
    info+= 'group law: t₁+t₂ (addition in 𝔾ₐ)';
  }
  if(Math.abs(t)>0.05 || m==='cusp'){
    svg.appendChild(SVG('circle',{cx:sx(px),cy:sy(py),r:5,fill:'var(--yellow)',stroke:'#fff','stroke-width':1}));
    const lbl=SVG('text',{x:sx(px)+9,y:sy(py)-4,'font-size':12,fill:'var(--yellow)'});
    lbl.textContent='t';
    svg.appendChild(lbl);
  }
  out.textContent=info;
}
tsl.addEventListener('input',render);
radios.forEach(r=>r.addEventListener('change',render));
render();

