    svg.appendChild(SVG('line',{x1:PAD,y1:PAD+i*cell,x2:W-PAD,y2:PAD+i*cell,stroke:'#1f2736','stroke-width':0.5}));
  }
  // axes labels
  const tx=SVG('text',{x:W/2,y:H-6,'font-size':11,fill:'var(--mute)','text-anchor':'middle'});
  tx.textContent='x ∈ F_'+p; svg.appendChild(tx);
  // points
  const pts=[];
  let singular=null;
  const D=mod(-16*(4*a*a*a+27*b*b),p);
  for(let x=0;x<p;x++){
    const rhs=mod(x*x*x+a*x+b,p);
    for(let y=0;y<p;y++){
      if(mod(y*y-rhs,p)===0){
        pts.push([x,y]);
