        if(mod(2*y,p)===0 && mod(3*x*x+a,p)===0) singular=[x,y];
      }
    }
  }
  for(const [x,y] of pts){
    const cx=PAD+(x+0.5)*cell, cy=H-PAD-(y+0.5)*cell;
    const isSing = singular && singular[0]===x && singular[1]===y;
    svg.appendChild(SVG('circle',{cx,cy,r:Math.max(2.2,cell*0.28),fill:isSing?'var(--pink)':'var(--green)'}));
  }
  const N = pts.length + 1; // +1 for point at infinity (O)
  let msg = 'y² = x³ + ('+a+')x + ('+b+')  over F_'+p+'\n';
  msg += 'Δ mod p = '+D+'\n';
  if(D!==0){
    msg += 'GOOD reduction.\n';
    msg += '|Ẽ(F_p)| = affine pts + O = '+pts.length+' + 1 = '+N+'\n';
    const ap = p+1-N;
    msg += 'a_p = p + 1 − |Ẽ(F_p)| = '+ap+'\n';
    msg += '|a_p| ≤ 2√p ≈ '+(2*Math.sqrt(p)).toFixed(3)+'  (Hasse) → '+ (Math.abs(ap)<=2*Math.sqrt(p)+1e-9?'ok.':'VIOLATED?!');
  } else {
    msg += 'BAD reduction; singular point '+(singular?'at ('+singular[0]+','+singular[1]+')':'(not seen as an affine point)')+'\n';
    // classify
    if(mod(a,p)===0 && mod(b,p)===0){
      msg += 'looks cuspidal (a ≡ b ≡ 0) → ADDITIVE.\n';
    } else {
      msg += 'nodal or cuspidal (see tangent-cone widget above).\n';
    }
    msg += '|Ẽ(F_p)| (naive, counting the singular point) = '+N;
  }
  out.textContent = msg;
}
