      svg.appendChild(SVG('text',{x,y:H-PADY+14,'font-size':10,fill:'var(--pink)','text-anchor':'middle'})).textContent='bad';
      rows.push({p,N:'(bad)',ap:'—'});
    } else {
      const N = pointCount(a,b,p);
      const ap = p+1-N;
      svg.appendChild(SVG('circle',{cx:x,cy:sy(N),r:4,fill:'var(--yellow)',stroke:'#000','stroke-width':0.4}));
