    const lbl=SVG('text',{x,y:H-PADY+14,'font-size':10,fill:'var(--mute)','text-anchor':'middle'});
    lbl.textContent=(dm===0?'':String(p));
    if(dm!==0) svg.appendChild(lbl);
  });
  // legend
  const lab1=SVG('text',{x:W/2,y:22,'font-size':12,fill:'var(--ink)','text-anchor':'middle'});
  lab1.textContent='|Ẽ(F_p)| vs. Hasse band [p+1−2√p, p+1+2√p]';
  svg.appendChild(lab1);
  // build readout
